import { serverCreateRoomRequestSchema } from '../../schemas/server/multiplayer/createRoom.js';
import { parse } from '../../utils/json.js';
import { handleError } from '../error.js';
export const createServerCreateRoomRouteHandler = (multiplayer) => async ({ req, res, localize, ctx }) => {
    if (!multiplayer.createHandler) {
        res.status(404).end();
        return;
    }
    const body = req.body;
    if (!(body instanceof Buffer)) {
        res.status(400).end();
        return;
    }
    const request = parse(body, serverCreateRoomRequestSchema);
    if (!request) {
        res.status(400).end();
        return;
    }
    const response = await multiplayer.createHandler(ctx);
    if (handleError(response, res, localize))
        return;
    res.json(response);
};
